cat ~/.openclaw/openclaw.json | python3 -c "
import json, sys
data = json.load(sys.stdin)
print('Top-level keys:', list(data.keys()))
# Chercher tout ce qui contient 'model' ou 'fallback'
def find_models(obj, path=''):
    if isinstance(obj, dict):
        for k, v in obj.items():
            find_models(v, f'{path}.{k}')
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            find_models(v, f'{path}[{i}]')
    elif isinstance(obj, str) and ('model' in path.lower() or 'fallback' in path.lower() or 'groq' in str(obj) or 'openrouter' in str(obj) or 'anthropic' in str(obj)):
        print(f'  {path} = {obj}')
find_models(data)
" 2>/dev/null | head -80

